import numpy as np
from collections import Counter

def solve(grid):
    g = np.array(grid)
    H, W = g.shape

    # Find background color
    bg = Counter(g.flatten()).most_common(1)[0][0]

    # Find all non-bg colors and their bounding boxes
    non_bg_colors = sorted(set(int(x) for x in g.flatten() if x != bg))

    color_bboxes = {}
    for c in non_bg_colors:
        positions = np.argwhere(g == c)
        r_min, c_min = positions.min(axis=0)
        r_max, c_max = positions.max(axis=0)
        color_bboxes[c] = (int(r_min), int(c_min), int(r_max), int(c_max))

    # Group colors with overlapping bounding boxes
    def bboxes_overlap(b1, b2):
        return not (b1[2] < b2[0] or b2[2] < b1[0] or b1[3] < b2[1] or b2[3] < b1[1])

    # Union-find grouping
    parent = {c: c for c in non_bg_colors}
    def find(x):
        while parent[x] != x:
            parent[x] = parent[parent[x]]
            x = parent[x]
        return x
    def union(a, b):
        pa, pb = find(a), find(b)
        if pa != pb:
            parent[pa] = pb

    for i, c1 in enumerate(non_bg_colors):
        for c2 in non_bg_colors[i+1:]:
            if bboxes_overlap(color_bboxes[c1], color_bboxes[c2]):
                union(c1, c2)

    groups = {}
    for c in non_bg_colors:
        root = find(c)
        groups.setdefault(root, []).append(c)

    group_list = list(groups.values())

    # Shape group has 1 color, template group has 2+
    if len(group_list) == 2:
        if len(group_list[0]) == 1 and len(group_list[1]) > 1:
            shape_colors, template_colors = group_list[0], group_list[1]
        elif len(group_list[1]) == 1 and len(group_list[0]) > 1:
            shape_colors, template_colors = group_list[1], group_list[0]
        else:
            # Both have same count - use fewer cells as shape
            shape_colors, template_colors = group_list[0], group_list[1]
    else:
        # Fallback: single color groups are shape candidates
        single = [g for g in group_list if len(g) == 1]
        multi = [g for g in group_list if len(g) > 1]
        shape_colors = single[0]
        template_colors = multi[0]

    # Get bounding boxes
    all_shape_positions = np.concatenate([np.argwhere(g == c) for c in shape_colors])
    sr_min, sc_min = all_shape_positions.min(axis=0)
    sr_max, sc_max = all_shape_positions.max(axis=0)
    shape = g[sr_min:sr_max+1, sc_min:sc_max+1]

    all_template_positions = np.concatenate([np.argwhere(g == c) for c in template_colors])
    tr_min, tc_min = all_template_positions.min(axis=0)
    tr_max, tc_max = all_template_positions.max(axis=0)
    template = g[tr_min:tr_max+1, tc_min:tc_max+1]

    th, tw = template.shape
    sh, sw = shape.shape

    output = np.full((sh * th, sw * tw), bg, dtype=int)

    for r in range(sh):
        for c in range(sw):
            if shape[r, c] != bg:
                output[r*th:(r+1)*th, c*tw:(c+1)*tw] = template

    return output.tolist()

